module parallel2serial
(
    input clk,
    input rst_n,
    input [3:0] d,
    output valid_out,
    output dout
);

input clk;
input rst_n;
input [3:0] d;
output valid_out;
output dout;

reg [3:0] data;
reg [1:0] cnt;
reg valid;
assign dout = data[3];
assign valid_out = valid;

always @(posedge clk or posedge rst_n) begin
    if (rst_n) begin
        cnt <= cnt + 1;
    end
    else begin
        if (cnt == 3) begin
            data <= d;
            cnt <= 0;
            valid <= 1;
        end
        else begin
            valid <= 0;
            data <= {data[2:0], data[3]};
            cnt <= cnt + 1;
        end
    end
end
endmodule
